package com.santiago.soberpath.data.local
import android.content.Context import androidx.room.Database import androidx.room.Room import androidx.room.RoomDatabase import androidx.sqlite.db.SupportSQLiteDatabase import com.santiago.soberpath.data.local.dao.DailyCheckInDao import com.santiago.soberpath.data.local.dao.HabitDao import com.santiago.soberpath.data.local.dao.MilestoneDao import com.santiago.soberpath.data.local.dao.MotivationReasonDao import com.santiago.soberpath.data.local.entity.DailyCheckInEntity import com.santiago.soberpath.data.local.entity.HabitEntity import com.santiago.soberpath.data.local.entity.MilestoneEntity import com.santiago.soberpath.data.local.entity.MotivationReasonEntity
@Database( entities = [ HabitEntity::class, DailyCheckInEntity::class, MotivationReasonEntity::class, MilestoneEntity::class ], version = 1, exportSchema = false ) abstract class SoberPathDatabase : RoomDatabase() { abstract fun habitDao(): HabitDao abstract fun dailyCheckInDao(): DailyCheckInDao abstract fun motivationReasonDao(): MotivationReasonDao abstract fun milestoneDao(): MilestoneDao
companion object { const val DATABASE_NAME = "soberpath.db"
fun build(context: Context): SoberPathDatabase { return Room.databaseBuilder( context, SoberPathDatabase::class.java, DATABASE_NAME ).addCallback(MilestoneSeedCallback()).build() } } }
private class MilestoneSeedCallback : RoomDatabase.Callback() { override fun onCreate(db: SupportSQLiteDatabase) { super.onCreate(db) db.execSQL("INSERT INTO milestones (id, title, daysRequired, achieved) VALUES ('ms_1', '1 dia', 1, 0)") db.execSQL("INSERT INTO milestones (id, title, daysRequired, achieved) VALUES ('ms_3', '3 dias', 3, 0)") db.execSQL("INSERT INTO milestones (id, title, daysRequired, achieved) VALUES ('ms_7', '7 dias', 7, 0)") db.execSQL("INSERT INTO milestones (id, title, daysRequired, achieved) VALUES ('ms_14', '14 dias', 14, 0)") db.execSQL("INSERT INTO milestones (id, title, daysRequired, achieved) VALUES ('ms_30', '30 dias', 30, 0)") db.execSQL("INSERT INTO milestones (id, title, daysRequired, achieved) VALUES ('ms_60', '60 dias', 60, 0)") db.execSQL("INSERT INTO milestones (id, title, daysRequired, achieved) VALUES ('ms_90', '90 dias', 90, 0)") } }

package com.santiago.soberpath.data.local.dao

import androidx.room.Dao
import androidx.room.Insert
import androidx.room.OnConflictStrategy
import androidx.room.Query
import com.santiago.soberpath.data.local.entity.DailyCheckInEntity
import kotlinx.coroutines.flow.Flow

@Dao
interface DailyCheckInDao {
    @Insert(onConflict = OnConflictStrategy.REPLACE)
    suspend fun insert(checkIn: DailyCheckInEntity)

    @Query("SELECT * FROM daily_check_ins WHERE habitId = :habitId ORDER BY date DESC")
    fun observeByHabitId(habitId: String): Flow<List<DailyCheckInEntity>>
}

package com.santiago.soberpath.data.local.dao

import androidx.room.Dao
import androidx.room.Insert
import androidx.room.OnConflictStrategy
import androidx.room.Query
import com.santiago.soberpath.data.local.entity.HabitEntity
import kotlinx.coroutines.flow.Flow

@Dao
interface HabitDao {
    @Insert(onConflict = OnConflictStrategy.REPLACE)
    suspend fun upsert(habit: HabitEntity)

    @Query("SELECT * FROM habits WHERE isActive = 1 LIMIT 1")
    fun observeActiveHabit(): Flow<HabitEntity?>

    @Query("SELECT * FROM habits WHERE id = :habitId LIMIT 1")
    suspend fun getById(habitId: String): HabitEntity?

    @Query("SELECT * FROM habits WHERE id = :habitId LIMIT 1")
    fun observeById(habitId: String): Flow<HabitEntity?>
}

package com.santiago.soberpath.data.local.dao

import androidx.room.Dao
import androidx.room.Insert
import androidx.room.OnConflictStrategy
import androidx.room.Query
import com.santiago.soberpath.data.local.entity.MilestoneEntity
import kotlinx.coroutines.flow.Flow

@Dao
interface MilestoneDao {
    @Insert(onConflict = OnConflictStrategy.REPLACE)
    suspend fun insertAll(milestones: List<MilestoneEntity>)

    @Query("SELECT * FROM milestones ORDER BY daysRequired ASC")
    fun observeAll(): Flow<List<MilestoneEntity>>
}

package com.santiago.soberpath.data.local.dao

import androidx.room.Dao
import androidx.room.Insert
import androidx.room.OnConflictStrategy
import androidx.room.Query
import com.santiago.soberpath.data.local.entity.MotivationReasonEntity
import kotlinx.coroutines.flow.Flow

@Dao
interface MotivationReasonDao {
    @Insert(onConflict = OnConflictStrategy.REPLACE)
    suspend fun insert(reason: MotivationReasonEntity)

    @Query("SELECT * FROM motivation_reasons WHERE habitId = :habitId ORDER BY createdAt DESC")
    fun observeByHabitId(habitId: String): Flow<List<MotivationReasonEntity>>
}

package com.santiago.soberpath.data.local.entity
import androidx.room.Entity import androidx.room.Index import androidx.room.PrimaryKey
@Entity( tableName = "daily_check_ins", indices = [Index(value = ["habitId"])]) data class DailyCheckInEntity( @PrimaryKey val id: String, val habitId: String, val date: String, val mood: String, val cravingLevel: Int, val note: String?, val completedPledge: Boolean )

package com.santiago.soberpath.data.local.entity
import androidx.room.Entity import androidx.room.PrimaryKey
@Entity(tableName = "habits") data class HabitEntity( @PrimaryKey val id: String, val name: String, val category: String, val startDate: String, val lastRelapseDate: String, val dailyCost: Double, val currency: String, val isActive: Boolean )

package com.santiago.soberpath.data.local.entity

import androidx.room.Entity
import androidx.room.PrimaryKey

@Entity(tableName = "milestones")
data class MilestoneEntity(
    @PrimaryKey val id: String,
    val title: String,
    val daysRequired: Int,
    val achieved: Boolean
)

package com.santiago.soberpath.data.local.entity
import androidx.room.Entity import androidx.room.Index import androidx.room.PrimaryKey
@Entity( tableName = "motivation_reasons", indices = [Index(value = ["habitId"])]) data class MotivationReasonEntity( @PrimaryKey val id: String, val habitId: String, val text: String, val createdAt: String )
